-- TEE-18: Multi-schedule ForeUp courses
-- Replace single-row-per-course with one-row-per-schedule (2,304 rows)
-- Filtered out simulator bays, lessons, fitting bays, etc.

-- Step 1: Drop old unique constraint, create new one that includes schedule_id
DROP INDEX IF EXISTS idx_courses_platform;
CREATE UNIQUE INDEX idx_courses_platform ON courses (platform, platform_course_id, platform_schedule_id);

-- Step 2: Remove existing ForeUp single-schedule rows
DELETE FROM courses WHERE platform = 'foreup';

